package org.apache.commons.math.linear;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.math.linear.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math.linear.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.linear.EigenDecompositionImpl;
import org.apache.commons.math.linear.TridiagonalTransformer;
import org.apache.commons.math.util.MathUtils;

import java.util.ArrayList;
import java.util.List;

import static org.junit.Assert.assertArrayEquals;

public class StepDefs {

    private double[] mainDiagonal;
    private double[] secondaryDiagonal;
    private double[] calculatedEigenvalues;
    private double[] expectedEigenvalues;

    @Given("a symmetric tridiagonal matrix with the following main diagonal:")
    public void given_a_symmetric_tridiagonal_matrix_with_main_diagonal(List<Double> mainDiag) {
        mainDiagonal = mainDiag.stream().mapToDouble(Double::doubleValue).toArray();
    }

    @Given("the following secondary diagonal:")
    public void given_the_secondary_diagonal(List<Double> secondaryDiag) {
        secondaryDiagonal = secondaryDiag.stream().mapToDouble(Double::doubleValue).toArray();
    }

    @When("the eigen decomposition is computed")
    public void when_eigen_decomposition_is_computed() {
        try {
            // Create a symmetric tridiagonal matrix from the diagonals
            int n = mainDiagonal.length;
            double[][] matrix = new double[n][n];

            // Fill the main diagonal
            for (int i = 0; i < n; i++) {
                matrix[i][i] = mainDiagonal[i];
            }

            // Fill the secondary diagonals
            for (int i = 0; i < n - 1; i++) {
                matrix[i][i + 1] = secondaryDiagonal[i];
                matrix[i + 1][i] = secondaryDiagonal[i];
            }

            // Compute eigenvalues using EigenDecomposition
            EigenDecompositionImpl decomposition = new EigenDecompositionImpl(matrix, 1e-12);
            calculatedEigenvalues = decomposition.getRealEigenvalues();

            // Sort eigenvalues for comparison (as ordering might vary)
            java.util.Arrays.sort(calculatedEigenvalues);
        } catch (Exception e) {
            throw new RuntimeException("Error computing eigen decomposition", e);
        }
    }

    @Then("the resulting eigenvalues should match the following reference values within 1.0e-3 tolerance:")
    public void then_resulting_eigenvalues_match_reference_values(List<Double> expectedValues) {
        expectedEigenvalues = expectedValues.stream().mapToDouble(Double::doubleValue).toArray();

        // Sort expected values for comparison
        java.util.Arrays.sort(expectedEigenvalues);

        // Check if the arrays are equal within tolerance
        assertArrayEquals("Eigenvalues should match within tolerance", expectedEigenvalues, calculatedEigenvalues, 1.0e-3);
    }
}

